import{_ as e,c as t,o,a2 as a}from"./chunks/framework.DdOM6S6U.js";const m=JSON.parse('{"title":"Overview & Architecture","description":"","frontmatter":{"sidebarPos":1,"sidebarTitle":"Overview & Architecture"},"headers":[],"relativePath":"guide/custom-auth-pages/overview.md","filePath":"guide/custom-auth-pages/overview.md","lastUpdated":null}'),i={name:"guide/custom-auth-pages/overview.md"},s=a('<h1 id="overview-architecture" tabindex="-1">Overview &amp; Architecture <a class="header-anchor" href="#overview-architecture" aria-label="Permalink to &quot;Overview &amp; Architecture&quot;">​</a></h1><h2 id="two-auth-components" tabindex="-1">Two Auth Components <a class="header-anchor" href="#two-auth-components" aria-label="Permalink to &quot;Two Auth Components&quot;">​</a></h2><h3 id="package-auth-ueauth" tabindex="-1">Package Auth (UeAuth) <a class="header-anchor" href="#package-auth-ueauth" aria-label="Permalink to &quot;Package Auth (UeAuth)&quot;">​</a></h3><ul><li><strong>Location</strong>: <code>packages/modularous/vue/src/js/components/Auth.vue</code></li><li><strong>Purpose</strong>: Minimal, slot-based layout. No app-specific content.</li><li><strong>Props</strong>: <code>slots</code>, <code>noDivider</code>, <code>noSecondSection</code>, <code>logoLightSymbol</code>, <code>logoSymbol</code></li><li><strong>Slots</strong>: <code>description</code>, <code>cardTop</code>, default (form), <code>bottom</code></li><li><strong>Banner area</strong>: Renders <code>&lt;slot name=&quot;description&quot; /&gt;</code> only when <code>noSecondSection</code> is false. No default content.</li><li><strong><code>inheritAttrs: false</code></strong>: Custom attributes (e.g. <code>bannerDescription</code>) are not applied to the root; they are intended for custom auth components.</li></ul><h3 id="custom-auth-uecustomauth" tabindex="-1">Custom Auth (UeCustomAuth) <a class="header-anchor" href="#custom-auth-uecustomauth" aria-label="Permalink to &quot;Custom Auth (UeCustomAuth)&quot;">​</a></h3><ul><li><strong>Location</strong>: <code>resources/vendor/modularity/js/components/Auth.vue</code> (published from package)</li><li><strong>Purpose</strong>: App-specific layouts (split layout, banner, custom branding)</li><li><strong>Props</strong>: Declare any props you need (e.g. <code>bannerDescription</code>, <code>bannerSubDescription</code>, <code>redirectButtonText</code>, <code>redirectUrl</code>)</li><li><strong>Activation</strong>: Set <code>auth_pages.component_name</code> to <code>ue-custom-auth</code> in your app config</li></ul><h2 id="attribute-flow" tabindex="-1">Attribute Flow <a class="header-anchor" href="#attribute-flow" aria-label="Permalink to &quot;Attribute Flow&quot;">​</a></h2><p>The auth layout blade passes all attributes to the auth component:</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $authComponentName </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> v-bind=&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($attributes)&#39;&gt;</span></span></code></pre></div><p>Attributes are built from (in merge order):</p><ol><li><code>auth_pages.layout</code> — default layout config</li><li><code>layoutPreset</code> — structural flags (e.g. <code>noSecondSection</code>)</li><li><code>auth_pages.attributes</code> — global attributes for all pages</li><li><code>pages.[pageKey].attributes</code> — per-page overrides</li></ol><p><strong>Full flexibility</strong>: Any attribute you add in config is passed to the auth component. Custom auth components declare the props they need and receive them automatically.</p><h2 id="config-sources" tabindex="-1">Config Sources <a class="header-anchor" href="#config-sources" aria-label="Permalink to &quot;Config Sources&quot;">​</a></h2><table><thead><tr><th>Config</th><th>Purpose</th></tr></thead><tbody><tr><td><code>config/merges/auth_pages.php</code></td><td>Package defaults (pages, layoutPresets)</td></tr><tr><td><code>modularity/auth_pages.php</code></td><td>App overrides (attributes, component_name)</td></tr><tr><td><code>config/merges/auth_component.php</code></td><td>Package UI config (formWidth, dividerText)</td></tr><tr><td><code>modularity/auth_component.php</code></td><td>App UI overrides</td></tr></tbody></table><p>Use <code>modularity/auth_pages.php</code> for deferred loading (when translator is needed for <code>__()</code> in attributes).</p>',15),r=[s];function c(n,d,l,u,h,p){return o(),t("div",null,r)}const b=e(i,[["render",c]]);export{m as __pageData,b as default};
